-- Data safety (2/2): COMMUNITY-type chats have no title of their own today;
-- backfill from the community name before dropping communityId so they don't
-- render as unnamed chats afterward.
UPDATE "chats" c SET title = cm.name
FROM "communities" cm
WHERE c."communityId" = cm.id AND c.title IS NULL;

